#include<bits/stdc++.h>
using namespace std;
#define endl '\n'
const int maxn=5e3+5,mod=1e8;
string a,b;
int lena,lenb,dp[2][maxn],num[2][maxn],t;
int main() {
	cin>>a>>b,lena=a.size(),lenb=b.size();
	for(int i=0; i<lenb; i++) num[0][i]=1;
	num[1][0]=1;
	for(int i=1; i<lena; i++,t^=1) {
		for(int j=1; j<lenb; j++) {
			num[t^1][j]=0;
			if(a[i-1]==b[j-1]) dp[t^1][j]=dp[t][j-1]+1,num[t^1][j]=num[t][j-1];
			else dp[t^1][j]=max(dp[t][j],dp[t^1][j-1]);
			if(dp[t^1][j]==dp[t][j]) num[t^1][j]=(0LL+num[t^1][j]+num[t][j])%mod;
			if(dp[t^1][j]==dp[t^1][j-1]) num[t^1][j]=(0LL+num[t^1][j]+num[t^1][j-1])%mod;
			if(a[i-1]!=b[j-1] && dp[t^1][j]==dp[t][j-1]) {
				num[t^1][j]=(num[t^1][j]-num[t][j-1]+0LL+mod)%mod;
			}
		}
	}
	cout<<dp[t][lenb-1]<<endl<<num[t][lenb-1];
	return 0;
}
